// MARK: - Secure Storage

final class SecureStorage {
    
    static let shared = SecureStorage()
    private let encryptionManager = EncryptionManager.shared
    private let fileManager = FileManager.default
    
    private var secureDirectory: URL {
        let documentsDir = fileManager.urls(for: .documentDirectory, in: .userDomainMask).first!
        let secureDir = documentsDir.appendingPathComponent(".secure_data", isDirectory: true)
        if !fileManager.fileExists(atPath: secureDir.path) {
            try? fileManager.createDirectory(at: secureDir, withIntermediateDirectories: true)
            // Exclude from backups
            var resourceValues = URLResourceValues()
            resourceValues.isExcludedFromBackup = true
            var mutableURL = secureDir
            try? mutableURL.setResourceValues(resourceValues)
        }
        return secureDir
    }
    
    private init() {}
    
    func saveSecurely<T: Codable>(_ object: T, forKey key: String) throws {
        let assessment = DeviceSecurityManager.shared.performSecurityAssessment()
        guard assessment.isSecure else {
            throw EncryptionManager.EncryptionError.deviceCompromised
        }
        
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        let data = try encoder.encode(object)
        let encryptedData = try encryptionManager.encrypt(data)
        
        let fileURL = secureDirectory.appendingPathComponent(encryptionManager.hashString(key))
        try encryptedData.write(to: fileURL, options: [.atomic, .completeFileProtection])
    }
    
    func loadSecurely<T: Codable>(forKey key: String, as type: T.Type) throws -> T {
        let assessment = DeviceSecurityManager.shared.performSecurityAssessment()
        guard assessment.isSecure else {
            throw EncryptionManager.EncryptionError.deviceCompromised
        }
        
        let fileURL = secureDirectory.appendingPathComponent(encryptionManager.hashString(key))
        let encryptedData = try Data(contentsOf: fileURL)
        let data = try encryptionManager.decrypt(encryptedData)
        
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        return try decoder.decode(type, from: data)
    }
    
    func deleteSecurely(forKey key: String) {
        let fileURL = secureDirectory.appendingPathComponent(encryptionManager.hashString(key))
        try? fileManager.removeItem(at: fileURL)
    }
    
    func wipeAllData() {
        try? fileManager.removeItem(at: secureDirectory)
        encryptionManager.wipeAllKeys()
    }
}

// MARK: - Biometric Authentication

final class BiometricAuthManager {
    
    enum BiometricError: Error, LocalizedError {
        case notAvailable
        case authenticationFailed
        case userCancelled
        case deviceCompromised
        
        var errorDescription: String? {
            switch self {
            case .notAvailable: return "Biometric authentication not available"
            case .authenticationFailed: return "Authentication failed"
            case .userCancelled: return "Authentication cancelled"
            case .deviceCompromised: return "Device security compromised"
            }
        }
    }
    
    static let shared = BiometricAuthManager()
    private init() {}
    
    var isBiometricAvailable: Bool {
        let context = LAContext()
        var error: NSError?
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }
    
    var biometricType: LABiometryType {
        let context = LAContext()
        var error: NSError?
        context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
        return context.biometryType
    }
    
    func authenticate(reason: String, completion: @escaping (Result<Bool, BiometricError>) -> Void) {
        // Check device security first
        let assessment = DeviceSecurityManager.shared.performSecurityAssessment()
        guard assessment.isSecure else {
            completion(.failure(.deviceCompromised))
            return
        }
        
        let context = LAContext()
        context.localizedCancelTitle = "Cancel"
        context.localizedFallbackTitle = "Use Passcode"
        
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            completion(.failure(.notAvailable))
            return
        }
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, error in
            DispatchQueue.main.async {
                if success {
                    completion(.success(true))
                } else if let laError = error as? LAError {
                    switch laError.code {
                    case .userCancel, .appCancel, .systemCancel:
                        completion(.failure(.userCancelled))
                    default:
                        completion(.failure(.authenticationFailed))
                    }
                } else {
                    completion(.failure(.authenticationFailed))
                }
            }
        }
    }
}

// MARK: - Transaction Processor

final class TransactionProcessor {
    
    enum TransactionError: Error, LocalizedError {
        case insufficientFunds
        case invalidAmount
        case accountNotFound
        case accountInactive
        case dailyLimitExceeded
        case deviceCompromised
        case authenticationRequired
        case processingError(String)
        
        var errorDescription: String? {
            switch self {
            case .insufficientFunds: return "Insufficient funds"
            case .invalidAmount: return "Invalid transaction amount"
            case .accountNotFound: return "Account not found"
            case .accountInactive: return "Account is inactive"
            case .dailyLimitExceeded: return "Daily transaction limit exceeded"
            case .deviceCompromised: return "Transaction blocked: device security compromised"
            case .authenticationRequired: return "Authentication required"
            case .processingError(let msg): return "Processing error: \(msg)"
            }
        }
    }
    
    static let shared = TransactionProcessor()
    
    private let secureStorage = SecureStorage.shared
    private let encryptionManager = EncryptionManager.shared
    private let dailyTransactionLimit: Decimal = 50000.00
    
    private var transactionQueue = DispatchQueue(label: "com.banking.transactionQueue", qos: .userInitiated)
    private let transactionLock = NSLock()
    
    private init() {}
    
    // MARK: - Transaction Processing
    
    func processTransaction(
        type: TransactionType,
        amount: Decimal,
        fromAccount: Account?,
        toAccount: Account?,
        description: String,
        requireBiometric: Bool = true,
        completion: @escaping (Result<Transaction, TransactionError>) -> Void
    ) {
        // Step 1: Device security check
        let assessment = DeviceSecurityManager.shared.performSecurityAssessment()
        guard assessment.isSecure else {
            AuditLogger.shared.log(event: .securityThreatDetected, details: "Transaction blocked due to device compromise")
            completion(.failure(.deviceCompromised))
            return
        }
        
        // Step 2: Validate transaction
        guard amount > 0 else {
            completion(.failure(.invalidAmount))
            return
        }
        
        // Step 3: Biometric authentication for sensitive transactions
        if requireBiometric && amount > 100 {
            BiometricAuthManager.shared.authenticate(reason: "Authenticate to process \(type.rawValue) of \(amount)") { [weak self] result in
                switch result {
                case .success:
                    self?.executeTransaction(type: type, amount: amount, fromAccount: fromAccount, toAccount: toAccount, description: description, completion: completion)
                case .failure:
                    completion(.failure(.authenticationRequired))
                }
            }
        } else {
            executeTransaction(type: type, amount: amount, fromAccount: fromAccount, toAccount: toAccount, description: description, completion: completion)
        }
    }
    
    private func executeTransaction(
        type: TransactionType,
        amount: Decimal,
        fromAccount: Account?,
        toAccount: Account?,
        description: String,
        completion: @escaping (Result<Transaction, TransactionError>) -> Void
    ) {
        transactionQueue.async { [weak self] in
            guard let self = self else { return }
            
            self.transactionLock.lock()
            defer { self.transactionLock.unlock() }
            
            do {
                // Validate accounts
                if let from = fromAccount {
                    guard from.isActive else {
                        DispatchQueue.main.async { completion(.failure(.accountInactive)) }
                        return
                    }
                    
                    if type == .withdrawal || type == .transfer || type == .payment {
                        guard from.balance >= amount else {
                            DispatchQueue.main.async { completion(.failure(.insufficientFunds)) }
                            return
                        }
                    }
                }
                
                // Check daily limit
                let todayTotal = try self.getTodayTransactionTotal(forAccountId: fromAccount?.id ?? toAccount?.id ?? "")
                guard todayTotal + amount <= self.dailyTransactionLimit else {
                    DispatchQueue.main.async { completion(.failure(.dailyLimitExceeded)) }
                    return
                }
                
                // Create transaction
                let transaction = Transaction(
                    id: UUID().uuidString,
                    type: type,
                    amount: amount,
                    currency: fromAccount?.currency ?? toAccount?.currency ?? "USD",
                    description: description,
                    fromAccountId: fromAccount?.id,
                    toAccountId: toAccount?.id,
                    timestamp: Date(),
                    status: .completed,
                    referenceNumber: self.generateReferenceNumber()
                )
                
                // Save transaction securely
                try self.saveTransaction(transaction)
                
                // Update account balances
                if var from = fromAccount, (type == .withdrawal || type == .transfer || type == .payment) {
                    from.balance -= amount
                    try self.updateAccount(from)
                }
                
                if var to = toAccount, (type == .deposit || type == .transfer) {
                    to.balance += amount
                    try self.updateAccount(to)
                }
                
                // Audit log
                AuditLogger.shared.log(
                    event: .transactionProcessed,
                    details: "Transaction \(transaction.referenceNumber): \(type.rawValue) \(amount) \(transaction.currency)"
                )
                
                DispatchQueue.main.async {
                    completion(.success(transaction))
                }
                
            } catch {
                DispatchQueue.main.async {
                    completion(.failure(.processingError(error.localizedDescription)))
                }
            }
        }
    }
    
    private func generateReferenceNumber() -> String {
        let timestamp = Int(Date().timeIntervalSince1970)
        let random = Int.random(in: 100000...999999)
        return "TXN\(timestamp)\(random)"
    }
    
    private func saveTransaction(_ transaction: Transaction) throws {
        var transactions = (try? secureStorage.loadSecurely(forKey: "transactions", as: [Transaction].self)) ?? []
        transactions.append(transaction)
        try secureStorage.saveSecurely(transactions, forKey: "transactions")
    }
    
    private func updateAccount(_ account: Account) throws {
        var accounts = (try? secureStorage.loadSecurely(forKey: "accounts", as: [Account].self)) ?? []
        if let index = accounts.firstIndex(where: { $0.id == account.id }) {
            accounts[index] = account
        }
        try secureStorage.saveSecurely(accounts, forKey: "accounts")
    }
    
    func getTransactions(forAccountId accountId: String) throws -> [Transaction] {
        let assessment = DeviceSecurityManager.shared.performSecurityAssessment()
        guard assessment.isSecure else {
            throw TransactionError.deviceCompromised
        }
        
        let allTransactions = (try? secureStorage.loadSecurely(forKey: "transactions", as: [Transaction].self)) ?? []
        return allTransactions.filter { $0.fromAccountId == accountId || $0.toAccountId == accountId }
            .sorted { $0.timestamp > $1.timestamp }
    }
    
    private func getTodayTransactionTotal(forAccountId accountId: String) throws -> Decimal {
        let transactions = try getTransactions(forAccountId: accountId)
        let calendar = Calendar.current
        let today = calendar.startOfDay(for: Date())
        
        return transactions
            .filter { calendar.startOfDay(for: $0.timestamp) == today && $0.isDebit }
            .reduce(Decimal.zero) { $0 + $1.amount }
    }
    
    func getAccounts() throws -> [Account] {
        let assessment = DeviceSecurityManager.shared.performSecurityAssessment()
        guard assessment.isSecure else {
            throw TransactionError.deviceCompromised
        }
        
        return (try? secureStorage.loadSecurely(forKey: "accounts", as: [Account].self)) ?? []
    }
}

// MARK: - Audit Logger

final class AuditLogger {
    
    enum AuditEvent: String {
        case transactionProcessed = "TRANSACTION_PROCESSED"
        case authenticationSuccess = "AUTH_SUCCESS"
        case authenticationFailure = "AUTH_FAILURE"
        case securityThreatDetected = "SECURITY_THREAT"
        case dataAccessed = "DATA_ACCESSED"
        case appLaunched = "APP_LAUNCHED"
        case sessionExpired = "SESSION_EXPIRED"
        case dataWiped = "DATA_WIPED"
    }
    
    struct AuditEntry: Codable {
        let id: String
        let event: String
        let details: String
        let timestamp: Date
        let deviceInfo: String
    }
    
    static let shared = AuditLogger()
    private let logQueue = DispatchQueue(label: "com.banking.auditLog", qos: .utility)
    
    private init() {}
    
    func log(event: AuditEvent, details: String) {
        logQueue.async {
            let entry = AuditEntry(
                id: UUID().uuidString,
                event: event.rawValue,
                details: details,
                timestamp: Date(),
                deviceInfo: self.getDeviceInfo()
            )
            
            // In production, send to secure server
            // For now, store locally with encryption
            var logs = (try? SecureStorage.shared.loadSecurely(forKey: "audit_logs", as: [AuditEntry].self)) ?? []
            logs.append(entry)
            
            // Keep only last 1000 entries locally
            if logs.count > 1000 {
                logs = Array(logs.suffix(1000))
            }
            
            try? SecureStorage.shared.saveSecurely(logs, forKey: "audit_logs")
            
            #if DEBUG
            print("[AUDIT] \(entry.event): \(entry.details) at \(entry.timestamp)")
            #endif
        }
    }
    
    private func getDeviceInfo() -> String {
        let device = UIDevice.current
        return "\(device.model)|\(device.systemName) \(device.systemVersion)"
    }
}

// MARK: - Session Manager

final class SessionManager {
    
    static let shared = SessionManager()
    
    private var sessionTimer: Timer?
    private let sessionTimeout: TimeInterval = 300 // 5 minutes
    private var lastActivityTime: Date = Date()
    private(set) var isAuthenticated: Bool = false
    
    var onSessionExpired: (() -> Void)?
    
    private init() {}
    
    func startSession() {
        let assessment = DeviceSecurityManager.shared.performSecurityAssessment()
        guard assessment.isSecure else {
            AuditLogger.shared.log(event: .securityThreatDetected, details: "Session start blocked - device compromised")
            return
        }
        
        isAuthenticated = true
        lastActivityTime = Date()
        startSessionTimer()
        AuditLogger.shared.log(event: .authenticationSuccess, details: "Session started")
    }
    
    func refreshActivity() {
        lastActivityTime = Date()
    }
    
    func endSession() {
        isAuthenticated = false
        sessionTimer?.invalidate()
        sessionTimer = nil
        AuditLogger.shared.log(event: .sessionExpired, details: "Session ended")
        onSessionExpired?()
    }
    
    private func startSessionTimer() {
        sessionTimer?.invalidate()
        sessionTimer = Timer.scheduledTimer(withTimeInterval: 30, repeats: true) { [weak self] _ in
            guard let self = self else { return }
            
            let elapsed = Date().timeIntervalSince(self.lastActivityTime)
            if elapsed >= self.sessionTimeout {
                self.endSession()
            }
            
            // Periodic security check during session
            let assessment = DeviceSecurityManager.shared.performSecurityAssessment()
            if !assessment.isSecure {
                AuditLogger.shared.log(event: .securityThreatDetected, details: "Security threat detected during active session")
                self.endSession()
                // Wipe sensitive data
                SecureStorage.shared.wipeAllData()
                AuditLogger.shared.log(event: .dataWiped, details: "Data wiped due to security threat")
            }
        }
    }
}

// MARK: - View Models

final class AccountViewModel: ObservableObject {
    @Published var accounts: [Account] = []
    @Published var transactions: [Transaction] = []
    @Published var selectedAccount: Account?
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?
    @Published var showSecurityAlert: Bool = false
    @Published var securityThreats: [DeviceSecurityManager.SecurityThreat] = []
    
    private let transactionProcessor = TransactionProcessor.shared
    
    init() {
        checkDeviceSecurity()
    }
    
    func checkDeviceSecurity() {
        let assessment = DeviceSecurityManager.shared.performSecurityAssessment()
        if !assessment.isSecure {
            securityThreats = assessment.threats
            showSecurityAlert = true
            AuditLogger.shared.log(
                event: .securityThreatDetected,
                details: "Threats: \(assessment.threats.map { $0.rawValue }.joined(separator: ", "))"
            )
        }
    }
    
    func loadAccounts() {
        isLoading = true
        errorMessage = nil
        
        do {
            accounts = try transactionProcessor.getAccounts()
            
            // If no accounts exist, create demo accounts
            if accounts.isEmpty {
                createDemoAccounts()
            }
        } catch {
            errorMessage = error.localizedDescription
        }
        
        isLoading = false
    }
    
    func loadTransactions(forAccount account: Account) {
        isLoading = true
        errorMessage = nil
        
        do {
            transactions = try transactionProcessor.getTransactions(forAccountId: account.id)
        } catch {
            errorMessage = error.localizedDescription
        }
        
        isLoading = false
    }
    
    func processTransaction(
        type: TransactionType,
        amount: Decimal,
        description: String,
        completion: @escaping (Bool) -> Void
    ) {
        guard let account = selectedAccount else {
            errorMessage = "No account selected"
            completion(false)
            return
        }
        
        SessionManager.shared.refreshActivity()
        isLoading = true
        
        transactionProcessor.processTransaction(
            type: type,
            amount: amount,
            fromAccount: type.isDebitType ? account : nil,
            toAccount: type.isCreditType ? account : nil,
            description: description
        ) { [weak self] result in
            self?.isLoading = false
            
            switch result {
            case .success(let transaction):
                self?.transactions.insert(transaction, at: 0)
                self?.loadAccounts() // Refresh balances
                completion(true)
            case .failure(let error):
                self?.errorMessage = error.localizedDescription
                completion(false)
            }
        }
    }
    
    private func createDemoAccounts() {
        let demoAccounts = [
            Account(
                id: UUID().uuidString,
                accountNumber: "1234567890",
                accountType: .checking,
                balance: 5432.10,
                currency: "USD",
                holderName: "John Doe",
                isActive: true
            ),
            Account(
                id: UUID().uuidString,
                accountNumber: "0987654321",
                accountType: .savings,
                balance: 25000.00,
                currency: "USD",
                holderName: "John Doe",
                isActive: true
            )
        ]
        
        try? SecureStorage.shared.saveSecurely(demoAccounts, forKey: "accounts")
        accounts = demoAccounts
    }
}

// MARK: - TransactionType Extensions

extension TransactionType {
    var isDebitType: Bool {
        return self == .withdrawal || self == .transfer || self == .payment
    }
    
    var isCreditType: Bool {
        return self == .deposit || self == .transfer
    }
}

