struct NewTransactionView: View {
    @ObservedObject var viewModel: AccountViewModel
    @Environment(\.dismiss) var dismiss
    
    @State private var selectedType: TransactionType = .deposit
    @State private var amountString: String = ""
    @State private var description: String = ""
    @State private var showResult: Bool = false
    @State private var transactionSuccess: Bool = false
    
    var body: some View {
        NavigationView {
            Form {
                Section("Transaction Type") {
                    Picker("Type", selection: $selectedType) {
                        ForEach(TransactionType.allCases, id: \.self) { type in
                            HStack {
                                Image(systemName: type.icon)
                                Text(type.rawValue)
                            }
                            .tag(type)
                        }
                    }
                    .pickerStyle(.segmented)
                }
                
                Section("Details") {
                    TextField("Amount", text: $amountString)
                        .keyboardType(.decimalPad)
                    
                    TextField("Description", text: $description)
                }
                
                if let account = viewModel.selectedAccount {
                    Section("Account") {
                        HStack {
                            Text(account.accountType.rawValue)
                            Spacer()
                            Text(account.maskedAccountNumber)
                                .foregroundColor(.secondary)
                        }
                        HStack {
                            Text("Balance")
                            Spacer()
                            Text(account.formattedBalance)
                                .foregroundColor(.secondary)
                        }
                    }
                }
                
                Section {
                    Button(action: processTransaction) {
                        HStack {
                            Spacer()
                            if viewModel.isLoading {
                                ProgressView()
                            } else {
                                Text("Process Transaction")
                                    .fontWeight(.semibold)
                            }
                            Spacer()
                        }
                    }
                    .disabled(amountString.isEmpty || description.isEmpty || viewModel.isLoading)
                }
                
                if let error = viewModel.errorMessage {
                    Section {
                        Text(error)
                            .foregroundColor(.red)
                            .font(.caption)
                    }
                }
            }
            .navigationTitle("New Transaction")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Cancel") { dismiss() }
                }
            }
            .alert(transactionSuccess ? "Success" : "Error", isPresented: $showResult) {
                Button("OK") {
                    if transactionSuccess { dismiss() }
                }
            } message: {
                Text(transactionSuccess ? "Transaction processed successfully" : (viewModel.errorMessage ?? "Transaction failed"))
            }
        }
    }
    
    private func processTransaction() {
        guard let amount = Decimal(string: amountString) else {
            viewModel.errorMessage = "Invalid amount"
            return
        }
        
        viewModel.processTransaction(
            type: selectedType,
            amount: amount,
            description: description
        ) { success in
            transactionSuccess = success
            showResult = true
        }
    }
}

